var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"위험해.","JPN":"危ない。","ENG":"This isn't good.","TWN":"危險。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND"},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신의 피가 녀석의 영혼을 태워 결계를 만들고 있다.","JPN":"疫病神の血が奴の魂を燃やして結界を作っている。","ENG":"The Plague God's blood is creating a barrier by burning her soul.","TWN":"瘟神血液正在燃燒她的靈魂產生結界。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주! 일단 물러서라! 지금 녀석에게 다가가면 너도 무사하지 못해!","JPN":"当主！　一旦引け！　今奴に近づいたら、お主も無事では済まないぞ！","ENG":"Lady Nanahara! Get back! If you get close to her now, I can't guarantee your safety!","TWN":"堂主！先退下！現在靠她太近你也會有危險！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그래서는 늦고 맙니다.","JPN":"それでは遅れてしまいます。","ENG":"By then, it will be too late.","TWN":"我怕再耽擱下去會太遲。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유를 혼자 괴로워하게 둘 수는 없어요.","JPN":"千冬を一人苦しませるわけにはいきません。","ENG":"I cannot let Chifuyu suffer alone.","TWN":"我不能放千冬一個人痛苦。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다가가는 것만으로도…… 살갗이 찢기는 것 같아.","JPN":"近づくだけでも……肌が切り裂かれるみたい。","ENG":"Just be getting close to her... I feel a thousand cuts ripping my skin.","TWN":"光是靠近她……我的皮膚就彷彿被撕裂一般。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_WIND_07"},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그래도……","JPN":"それでも……","ENG":"But still...","TWN":"就算如此……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어떻게든 닿아야 해.","JPN":"どにかして行かなければ。","ENG":"I must reach her.","TWN":"無論如何我都要靠近她。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"으윽……!","JPN":"ううっ……！","ENG":"Ngh...!","TWN":"呃啊……！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크아아아아아!!!!</color>","JPN":"<color=#ff3636>グアアアアア！！！！</color>","ENG":"<color=#ff3636>Groarr!!</color>","TWN":"<color=#ff3636>呃啊啊啊啊啊！！！</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"뭘 하고 있는 거냐, 나는…….","JPN":"何をやっているんだ、私は……","ENG":"What am I even doing...?","TWN":"我，到底在做什麼……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"짐승이나 된 것처럼 고함이나 지르고 있고.","JPN":"獣になったみたいに叫んでばかり。","ENG":"I'm like an uncontrollable beast, roaring at the top of my lungs.","TWN":"我彷彿像野獸般，在那嚎叫。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"당주님?","JPN":"当主？","ENG":"Lady Nanahara?","TWN":"堂主？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"지금 내가…… 당주님을 해치려고 하는 건가?","JPN":"今私が……当主を攻撃しようとしているのか？","ENG":"Am I... trying to harm her?","TWN":"我現在……是要傷害堂主嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"네 평생을 걸었던 사람을 눈 앞에 두고…….","JPN":"一生をかけて守ろうとした人を目の前にして……","ENG":"She is the one person I swore to protect...","TWN":"我賭上一輩子要守護的人，就在我面前……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"넌 고작 이런 결말을 위해 지금껏 노력했던 거냐.","JPN":"お前はこんな結末を迎えるために今まで頑張ってきたのか。","ENG":"Did I go through everything just so it could end like this?","TWN":"難道我是因為要得到這種結局，才努力到現在的嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"견뎌.","JPN":"耐えろ。","ENG":"Endure it.","TWN":"堅持下去。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"적어도 마지막만큼은……","JPN":"せめて最後だけは……","ENG":"At least until the end...","TWN":"至少在我人生的最後……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>네가 한 맹세를 지켜보이란 말이다.</color>","JPN":"<color=#ff3636>自分の誓いを守ってみせろ。</color>","ENG":"<color=#ff3636>Keep your oath, Chifuyu.</color>","TWN":"<color=#ff3636>要讓你守住你的誓言。</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"결계가 사라졌어?","JPN":"結界が消えた？","ENG":"The barrier's gone?","TWN":"結界消失了？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주! 지금이다!","JPN":"当主！　今じゃ！","ENG":"Lady Nanahara! NOW!","TWN":"堂主！就是現在！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하아아앗!!!","JPN":"はあああっ！！！","ENG":"Haaaaa!!!!","TWN":"嚇啊啊啊！！！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"돌이켜보면……","JPN":"思い返してみれば……","ENG":"Looking back...","TWN":"現在回想起來……"},"stage":{"bg":"NANAHARA2_01","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"가문연합의 당주를 지킨다는 거창한 대의명분 때문에 검을 쥔 것이 아니었다.","JPN":"連合の当主を守るという大層な大義のために刀を持ったわけではなかった。","ENG":"I did not decide to wield this sword for some greater good of protecting the head of the Family Alliance.","TWN":"我拿起劍的原因，並不是保護家族聯盟的堂主這種冠冕堂皇的理由。"},"stage":{"bg":"NANAHARA2_01","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"단지 사랑하는 언니의 곁을 지키고,","JPN":"ただ愛する姉さんのそばを守り、","ENG":"I just wanted to keep my beloved sister by my side,","TWN":"我只是想守在我深愛的姊姊身邊，"},"stage":{"bg":"NANAHARA2_01","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"같이 힘들어하고,","JPN":"ともに苦しみ、","ENG":"Go through hardships together,","TWN":"成為可以和她一起分擔痛苦……"},"stage":{"bg":"NANAHARA2_01","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"어깨를 맞대며 서로 의지하는……","JPN":"肩を寄せてお互いを必要とする……","ENG":"Stand shoulder to shoulder, and become someone she can rely on...","TWN":"一起並肩作戰、互相依靠……"},"stage":{"bg":"NANAHARA2_01","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"……그런 동생이 되고 싶을 뿐이었다.","JPN":"……そんな妹になりたかっただけだった。","ENG":"...That is the kind of little sister I wanted to be...","TWN":"……的妹妹而已。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유.","JPN":"千冬。","ENG":"Chifuyu.","TWN":"千冬。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"난 말이야. 바람의 목소리를 잃고 나서 줄곧 방황했어.","JPN":"私ね、風の声を失ってからずっと迷っていたの。","ENG":"In all truth, I have been feeling lost ever since I lost the ability to hear the voice of wind.","TWN":"其實我在失去風聲後一直很迷惘。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어떤 결정을 내려도 틀린 길로만 가는 것 같아서 불안했어.","JPN":"どんな選択をしても間違っているようで不安だった。","ENG":"Every decision I made, I was anxious because it felt like I was leading everyone down the wrong path.","TWN":"因為好像不管我做什麼決定，都只是選擇走上錯誤的路，所以我很不安。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런데…… 이 순간만큼은…… 안심이 돼.","JPN":"なのに……この瞬間だけは……安心する。","ENG":"But... In this very moment... I feel assured.","TWN":"但是……我現在……卻很安心。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"내가 미래를 알 수 없더라도, 이 선택만큼은…… 절대 후회하지 않으니까.","JPN":"私に未来がわからなくても、この選択だけは……絶対に後悔しないから。","ENG":"I do not know what the future holds, but the choice I make here... I will never regret.","TWN":"因為雖然我無法得知未來，但這個選擇……我是絕對不會後悔的。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 미안해.","JPN":"そして、ごめんね。","ENG":"Also, I am sorry.","TWN":"還有，對不起。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"또 이렇게 내 멋대로 결정해버려서……","JPN":"またこんな風に私が勝手に決めちゃって……","ENG":"I am sorry to have made a decision without talking to you first...","TWN":"我又再次自作主張……"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……정말 미안해.","JPN":"……本当にごめん。","ENG":"...Forgive me.","TWN":"……真的很抱歉。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님……?","JPN":"当主……？","ENG":"My lady...?","TWN":"堂主……？"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이 피는 대체…….","JPN":"この血はいったい……","ENG":"What is this blood...?","TWN":"這血究竟是……"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언니……?","JPN":"姉上……？","ENG":"Sis...?","TWN":"姊姊……？"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"치후유님이 의식을 회복하셨군요. 어떻게 이런 일이……?","JPN":"千冬様が意識を取り戻しましたね。いったいどうやって……？","ENG":"Miss Chifuyu has regained consciousness. But how...?","TWN":"千冬恢復意識了，怎麼會這樣……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"설마 당주님께서…… 그때처럼 신력으로 치후유님을 구하신 겁니까?","JPN":"まさかご当主様が……あの時のように神力で千冬様を助けたのですか？","ENG":"Did Lady Nanahara... use her divine powers to save Chifuyu again?","TWN":"難道堂主她……跟上次一樣用神力拯救千冬嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그런 게 아니야.","JPN":"そういうものではない。","ENG":"That's not it.","TWN":"不是那樣的。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"작은 당주는 바람의 목소리를 잃은 시점에서 이미 신력을 잃었다.","JPN":"チビ当主は風の声を失った時点ですでに神力を失っている。","ENG":"Ladychild had lost all her divine powers when she couldn't hear the voice of wind.","TWN":"小堂主在失去風聲的那一刻起便已失去神力。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"저건……","JPN":"あれは……","ENG":"What she is doing right now is...","TWN":"她……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……천총운검으로 자신을 바쳐 역신을 잠재운 거야.","JPN":"……天叢雲剣で自身を生贄に疫病神を眠らせたのじゃ。","ENG":"...Sacrificing herself with the Sword of Kusanagi to put the Plague God to rest.","TWN":"……她將自己獻給天叢雲劍使瘟神沉睡。"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"어째서인가요.","JPN":"どうしてですか。","ENG":"But why...?","TWN":"為什麼？"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 역신을 깨울 존재라고 하셨으면서……","JPN":"私が疫病神を目覚めさせる存在だと言っておいて……","ENG":"You told me I was the one to awaken the Plague God...","TWN":"明明說過我的存在會喚醒瘟神……"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언니는 왜 저 같은 것 때문에……","JPN":"姉上はどうして私なんかのために……","ENG":"Why would you do something like this for me...?","TWN":"姊姊為什麼要為了我這種人……"},"stage":{"bg":"NANAHARA2_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그야 너희 원본이 무능했기 때문이지.","JPN":"そりゃ、オリジナルが無能だったからでしょ。","ENG":"Well, that's because the Original is incompetent, duh.","TWN":"那是因為你們的正本無能。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"틀린 결정이란 걸 알면서도 감정에 휩쓸려서 그런 실수를 저지르는 거야. 하등하니까.","JPN":"間違っていると知りながらも感情に流されてあんな過ちを犯しちゃうのよ。下等らしいわね。","ENG":"She lets her emotions take over, knowing it's a mistake and will end badly. That's because she's inferior.","TWN":"明知道是錯誤的決定，還是會被感情左右而犯下錯誤。因為她是低等生物。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"어이, 뿔 달린 짐승. 필사적으로 노력했지만 결국 실패한 기분은 어때?","JPN":"ねえ、角の生えた獣。必死に頑張って結局失敗した気持ちはどう？","ENG":"Hey, horned beast. How's it feel to fail while knowing you gave it your all?","TWN":"喂，長角的禽獸，你拚死努力的結果是失敗，心情如何？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"절망스러워? 아니면 화가 나?","JPN":"絶望？　それとも怒り？","ENG":"Are you devastated? Or maybe angry?","TWN":"絕望嗎？還是憤怒？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"미래를 안다면서 그런 뻔한 질문이나 지껄이려고 쫓아온 게냐?","JPN":"未来を知っているのにそんな当たり前の質問をしにわざわざ来たのか？","ENG":"Did you chase us all the way here to ask obvious questions about what you already know the answer to?","TWN":"你明知道未來的事，還特地跑回來問我這種答案很明顯的問題嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아니. 그냥 썩은 표정을 직접 보고 싶었을 뿐이야.","JPN":"いえ。渋い顔をしているところを直接見たかっただけ。","ENG":"No, I just wanted to see your rotten expression in person.","TWN":"不，我就是只想親眼看你挫敗的表情而已。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그리고 난 아버지의 명령대로 신의 그릇을 가지러 왔거든.","JPN":"それとお父様の命令通り、神の器を取りに来たの。","ENG":"Also, I'm here on father's orders to bring back the vessel.","TWN":"另外，父親命我來拿回神的器皿。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"너희 원본이 목숨을 바쳐 깨끗하게 씻어낸, 아주 안정된 신의 그릇을 말이야.","JPN":"オリジナルが命をかけてきれいにしてくれた、とても安定している神の器をね。","ENG":"The stabilized vessel that your Original sacrificed her life to cleanse.","TWN":"那個在正本獻上生命後，得以被洗淨而處於安定狀態的器皿。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……그런 거였군.","JPN":"……そうじゃったか。","ENG":"...So that's why you're here.","TWN":"……原來是這樣。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"처음부터 이렇게 될 운명이었던 건가.","JPN":"最初からこうなる運命じゃったか。","ENG":"It was destined to be this way from the beginning.","TWN":"從一開始就是這樣的命運嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이제야 알겠어?","JPN":"やっと気づいたの？","ENG":"Now do you get it?","TWN":"你現在才知道嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"너희가 아무리 발버둥 쳐봐야 내가 관측하는 미래를 벗어나지 못한다는 걸.","JPN":"お前たちがいくらあがいても私が見ている未来から逃れることはできないということに。","ENG":"No matter how hard you struggle, you can't stray from my foresight.","TWN":"不管你們怎麼掙扎，都無法脫離我觀測到的未來的。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"지금은 그렇게 생각할지도 모르지.","JPN":"今はそう考えているかもしれぬ。","ENG":"That's what you think now.","TWN":"你現在或許會那麼認為，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 내가 말하지 않았더냐?","JPN":"しかし、言ったじゃろう？","ENG":"But didn't I say?","TWN":"但我沒說過嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너 같이 무지한 녀석은, 결국 그런 힘에 의존하다 파멸하고 말 거라고!","JPN":"お主のような無知な奴は、結局そんな力に頼って破滅してしまうと！","ENG":"Fools like you eventually perish by relying too much on that power!","TWN":"像你這種無知的傢伙，一旦倚靠那股力量後，最終只能走向毀滅！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"마지막까지 안쓰러운 현실부정이네.","JPN":"最後まで現実逃避とはお気の毒。","ENG":"You're clearly delusional. How pitiful.","TWN":"到現在還不肯認清現實呢。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"자.","JPN":"さあ。","ENG":"Now then.","TWN":"來吧，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이제 너 하나만 남았어.","JPN":"これでお前一人残ったわ。","ENG":"There's only you left.","TWN":"現在就只剩下你。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아버지의 계획대로.","JPN":"お父様の計画通りに。","ENG":"As according to father's plan.","TWN":"就如同父親的計畫。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"두려워 할 죽음이 없다는 건 비단 자기 목숨을 두고 하는 얘기만이 아니다.","JPN":"恐れるべき死がないというのは、己の命のみを指して言っているのではないのじゃ。","ENG":"To be unafraid of death goes beyond your own life.","TWN":"所謂無懼死亡，並不單指犧牲自己的性命。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너도 네 목숨만큼 중히 여기는 것이 하나쯤은 있지 않느냐?","JPN":"お主とてその命と同じくらい大切にしているものが一つくらいはあるじゃろう？","ENG":"Don’t you have something dear to you, enough to sacrifice your own life for?","TWN":"你的生命中有一個如自己性命般重要的人吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"예정에 없던 가문의 아이가 태어나……","JPN":"前例のない子どもが生まれ……","ENG":"The unexpected child...","TWN":"不在家族預期內出生的孩子……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"역신을 깨우리라.","JPN":"疫病神の眠りを覚ますだろう。","ENG":"...shall awaken the Plague God.","TWN":"……，會喚醒瘟神。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>아이</color>가 바로 치후유입니다.","JPN":"あの<color=#ffd34c>子</color>が千冬です。","ENG":"That <color=#ffd34c>child</color> is you, Chifuyu.","TWN":"那個<color=#ffd34c>孩子</color>就是千冬。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"죽음 같은 건 두렵지 않다고 생각했다.","JPN":"死なんて怖くないと思った。","ENG":"I thought I was never afraid of death.","TWN":"我以為自己並不畏懼死亡。"},"stage":{"bg":"NANAHARA2_03","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_6"},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"당주님을 위해서라면 내 목숨도 아깝지 않다고 생각했으니까.","JPN":"当主のためなら自分の命も惜しくないと思ったから。","ENG":"I thought my life would be worthwhile if it was for Lady Nanahara.","TWN":"因為我可以為堂主犧牲性命在所不惜。"},"stage":{"bg":"NANAHARA2_03","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_7-3"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 이제는 알고 있다.","JPN":"でも今は知っている。","ENG":"But now I know.","TWN":"但現在我知道，"},"stage":{"bg":"NANAHARA2_06","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_8"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 두려워한 죽음이 무엇이었는가를.","JPN":"私が恐れていた死が何だったのかを。","ENG":"What kind of death I feared.","TWN":"我所畏懼的死亡是什麼。"},"stage":{"bg":"NANAHARA2_06","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_9-3"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 나는 이제……","JPN":"そして私にはもう……","ENG":"And now...","TWN":"還有，現在我……"},"stage":{"bg":"NANAHARA2_06","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_10-3"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"두려워 할 죽음이 없다.","JPN":"恐れる死はない。","ENG":"I have no death to fear.","TWN":"無懼死亡。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_11"},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"역신베기는…… 두려워 할 죽음이 없는 무사가 자신의 목숨을 바쳐 완성되리라.","JPN":"大蛇薙剣は……恐れるべき死のない武士が自らの命を捧げることにより完成するであろう。","ENG":"Completed shall Orochinagi be... with the life of a warrior unafraid of all death.","TWN":"瘟神斬……必須由無懼死亡的武士獻上自己的性命才能完成。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_13"},{"id":"L36_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"응? 뭐라는 거야?","JPN":"ん？　何を言ってるの？","ENG":"Hmm? What are you talking about?","TWN":"嗯？你在說什麼？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그러니 한 번 겨뤄보자.","JPN":"だから、やってみよう。","ENG":"So let us fight.","TWN":"所以，來一較高下吧！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_14"},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"네놈과 나…… 둘 중 누가 더 강한 검인지.","JPN":"お前と私……どちらがより強い剣なのか。","ENG":"You and me... Let us see who is the stronger blade.","TWN":"你和我……究竟誰更強。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_15"},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"후훗, 그렇게 깨져놓고도 아직 단념을 못하는 거야?","JPN":"ふふっ、それだけやられておいてまだ懲りてないの？","ENG":"Fuu fuu. Still not giving up after getting pummeled to the ground?","TWN":"呵呵，都已經慘成這樣還不死心嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"너무 서두를 것 없어.","JPN":"急ぐことはないわ。","ENG":"There's no need to hurry.","TWN":"別心急。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"날 상대하고 싶으면 아버지의 군대를 먼저 처리해야 할 테니까.","JPN":"私とやりたければ、まずお父様の軍隊を倒すことね。","ENG":"Because you'll have to face father's army before you can fight me.","TWN":"想和我較量，你得先解決掉父親的軍隊。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};